import React from "react";
import "./About.css";

const About = () => {
  return (
    <div className="about-page">
      <div className="about-container">
        <h2>Про нас</h2>
        <p>
          Наша платформа створена для пошуку та реєстрації на професійні події.
          Ми допомагаємо користувачам знаходити актуальні семінари, воркшопи та
          конференції у своїй сфері та зручно реєструватися на них.
        </p>
        <p>
          Адміністратори можуть додавати нові події, а користувачі реєструватися
          лише на конкретні заходи.
        </p>
      </div>

      <footer className="footer">
        <p>© 2026 Платформа подій. Всі права захищені.</p>
        <div className="footer-links">
          <a href="/about">Про нас</a>
          <a href="/news">Новини</a>
          <a href="/events">Події</a>
        </div>
      </footer>
    </div>
  );
};

export default About;
